function _addSigners(address account, bytes[] memory newSigners) internal virtual override {
    uint256 newSignersLength = newSigners.length;
    for (uint256 i = 0; i < newSignersLength; i++) {
        (uint256 deadline, bytes memory signer, bytes memory signature) = abi.decode(
            newSigners[i],
            (uint256, bytes, bytes)
        );
        require(deadline > block.timestamp, ERC7579MultisigExpiredConfirmation(deadline));
        require(
            SignatureChecker.isValidSignatureNow(signer, _signableConfirmationHash(account, deadline), signature),
            ERC7579MultisigInvalidConfirmationSignature(signer)
        );
        newSigners[i] = signer; // Replace the ABI-encoded value with the signer
    }
    super._addSigners(account, newSigners);
}

function isValidSignature(bytes32 hash, bytes calldata signature) public view virtual returns (bytes4) {
    // check signature length is enough for extraction
    if (signature.length >= 20) {
        (address module, bytes calldata innerSignature) = _extractSignatureValidator(signature);
        // if module is not installed, skip
        if (isModuleInstalled(MODULE_TYPE_VALIDATOR, module, Calldata.emptyBytes())) {
            // try validation, skip any revert
            try IERC7579Validator(module).isValidSignatureWithSender(msg.sender, hash, innerSignature) returns (
                bytes4 magic
            ) {
                return magic;
            } catch {}
        }
    }
    return bytes4(0xffffffff);
}

function getBorrowRateInternal(
    uint256 cash,
    uint256 borrows,
    uint256 reserves
) internal view returns (uint256) {
    uint256 util = utilizationRate(cash, borrows, reserves);

    if (util <= kink) {
        return util.mul(multiplierPerBlock).div(1e18).add(baseRatePerBlock);
    } else {
        uint256 normalRate = kink.mul(multiplierPerBlock).div(1e18).add(
            baseRatePerBlock
        );
        uint256 excessUtil = util.sub(kink);
        return
            excessUtil.mul(jumpMultiplierPerBlock).div(1e18).add(
                normalRate
            );
    }
}

function simplePermit2(
    ERC20 token,
    address owner,
    address spender,
    uint256 amount,
    uint256 deadline,
    uint8 v,
    bytes32 r,
    bytes32 s
) internal {
    (,, uint48 nonce) = PERMIT2.allowance(owner, address(token), spender);

    PERMIT2.permit(
        owner,
        IAllowanceTransfer.PermitSingle({
            details: IAllowanceTransfer.PermitDetails({
                token: address(token),
                amount: amount.toUint160(),
                // Use an unlimited expiration because it most
                // closely mimics how a standard approval works.
                expiration: type(uint48).max,
                nonce: nonce
            }),
            spender: spender,
            sigDeadline: deadline
        }),
        bytes.concat(r, s, bytes1(v))
    );
}

function deal(address token, address to, uint256 give, bool adjust) internal virtual {
    // get current balance
    (, bytes memory balData) = token.staticcall(abi.encodeWithSelector(0x70a08231, to));
    uint256 prevBal = abi.decode(balData, (uint256));

    // update balance
    _stdstore.target(token).sig(0x70a08231).with_key(to).checked_write(give);

    // update total supply
    if (adjust) {
        (, bytes memory totSupData) = token.staticcall(abi.encodeWithSelector(0x18160ddd));
        uint256 totSup = abi.decode(totSupData, (uint256));
        if (give < prevBal) {
            totSup -= (prevBal - give);
        } else {
            totSup += (give - prevBal);
        }
        _stdstore.target(token).sig(0x18160ddd).checked_write(totSup);
    }
}

function mintShares(address account, uint256 shares, uint256 totalSupply) internal {
    if (totalSupply == 0) return;

    fundsAsset.mint(address(this), totalSupply);
    fundsAsset.approve(address(pool), totalSupply);

    uint256 otherShares = totalSupply - shares;

    if (shares != 0) {
        pool.mint(shares, address(account));
    }

    if (otherShares != 0) {
        pool.mint(otherShares, address(this));
    }

    fundsAsset.burn(address(pool), totalSupply);  // Burn so that assets can be minted into the pool in other functions.
}

function createMarket(MarketParams memory marketParams) external {
    Id id = marketParams.id();
    require(isIrmEnabled[marketParams.irm], ErrorsLib.IRM_NOT_ENABLED);
    require(isLltvEnabled[marketParams.lltv], ErrorsLib.LLTV_NOT_ENABLED);
    require(market[id].lastUpdate == 0, ErrorsLib.MARKET_ALREADY_CREATED);

    // Safe "unchecked" cast.
    market[id].lastUpdate = uint128(block.timestamp);
    idToMarketParams[id] = marketParams;

    emit EventsLib.CreateMarket(id, marketParams);

    // Call to initialize the IRM in case it is stateful.
    if (marketParams.irm != address(0)) IIrm(marketParams.irm).borrowRate(marketParams, market[id]);
}

function testAuthorizationWithSig(Authorization memory authorization, uint256 privateKey) public {
    authorization.isAuthorized = true;
    authorization.deadline = bound(authorization.deadline, block.timestamp, type(uint256).max);

    // Private key must be less than the secp256k1 curve order.
    privateKey = bound(privateKey, 1, type(uint32).max);
    authorization.nonce = 0;
    authorization.authorizer = vm.addr(privateKey);

    Signature memory sig;
    bytes32 digest = SigUtils.getTypedDataHash(morpho.DOMAIN_SEPARATOR(), authorization);
    (sig.v, sig.r, sig.s) = vm.sign(privateKey, digest);

    morpho.setAuthorizationWithSig(authorization, sig);

    assertEq(morpho.isAuthorized(authorization.authorizer, authorization.authorized), true);
    assertEq(morpho.nonce(authorization.authorizer), 1);
}

function _boundUnhealthyPosition(uint256 amountCollateral, uint256 amountBorrowed, uint256 priceCollateral)
        internal
        view
        returns (uint256, uint256, uint256)
    {
        priceCollateral = bound(priceCollateral, MIN_COLLATERAL_PRICE, MAX_COLLATERAL_PRICE);
        amountBorrowed = bound(amountBorrowed, MIN_TEST_AMOUNT, MAX_TEST_AMOUNT);

        uint256 maxCollateral =
            amountBorrowed.wDivDown(marketParams.lltv).mulDivDown(ORACLE_PRICE_SCALE, priceCollateral);
        amountCollateral = bound(amountCollateral, 0, Math.min(maxCollateral, MAX_COLLATERAL_ASSETS));

        vm.assume(amountCollateral > 0 && amountCollateral < maxCollateral);
        return (amountCollateral, amountBorrowed, priceCollateral);
    }

