function verify(
    bytes32 messageHash,
    bytes32 r,
    bytes32 s,
    bytes32 qx,
    bytes32 qy
) internal view returns (bool success) {
    // EIP-7951 precompile input: hash(32) + r(32) + s(32) + x(32) + y(32) = 160 bytes
    bytes memory input = abi.encodePacked(messageHash, r, s, qx, qy);

    bytes memory output = new bytes(32);

    assembly {
        success := staticcall(
            gas(),
            0x100, // EIP-7951 P-256 precompile address
            add(input, 32),
            mload(input), // 160 bytes
            add(output, 32),
            32 // Output is 32 bytes
        )
    }

    // Precompile returns 32 bytes: 0x00...01 for valid, 0x00...00 for invalid
    if (success) {
        success = (output[31] == bytes1(0x01));
    }
}

function verifySignature(
    bytes memory name,
    RRUtils.SignedSet memory rrset,
    RRSetWithSignature memory data,
    bytes memory proof
) internal view {
    // o  The RRSIG RR's Signer's Name field MUST be the name of the zone
    //    that contains the RRset.
    if (!name.isSubdomainOf(rrset.signerName)) {
        revert InvalidSignerName(name, rrset.signerName);
    }

    RRUtils.RRIterator memory proofRR = proof.iterateRRs(0);
    // Check the proof
    if (proofRR.dnstype == DNSTYPE_DS) {
        verifyWithDS(rrset, data, proofRR);
    } else if (proofRR.dnstype == DNSTYPE_DNSKEY) {
        verifyWithKnownKey(rrset, data, proofRR);
    } else {
        revert InvalidProofType(proofRR.dnstype);
    }
}

function _resolveAddress(
    bytes calldata data,
    bytes calldata context
) internal pure returns (bytes memory) {
    (, uint256 coinType) = abi.decode(data[4:], (bytes32, uint256));
    bytes memory value;
    // Per https://docs.ens.domains/ensip/11#specification
    if (coinType & 0x80000000 != 0) {
        value = _findValue(
            context,
            bytes.concat(
                "a[e",
                bytes((coinType & 0x7fffffff).toString()),
                "]="
            )
        );
    } else {
        value = _findValue(
            context,
            bytes.concat("a[", bytes(coinType.toString()), "]=")
        );
    }
    if (value.length == 0) {
        return value;
    }
    (address record, bool valid) = value.hexToAddress(2, value.length);
    if (!valid) revert InvalidAddressFormat(value);
    return abi.encode(record);
}

function run(string[] memory inputs) internal returns (CommandResult) {
    try vulcan.hevm.tryFfi(inputs) returns (VmSafe.FfiResult memory ffiResult) {
        CommandOutput memory output;

        output.exitCode = ffiResult.exitCode;
        output.stdout = ffiResult.stdout;
        output.stderr = ffiResult.stderr;
        output.command = Command(inputs);

        return Ok(output);
    } catch Error(string memory message) {
        return CommandError.NotExecuted(message).toCommandResult();
    } catch (bytes memory data) {
        string memory message = abi.decode(removeSelector(data), (string));
        return CommandError.NotExecuted(message).toCommandResult();
    }
}

function toHaveRevertedWith(_CallExpectation memory self, bytes4 expectedSelector, string memory message)
        internal
    {
        self.toHaveReverted();

        bytes4 actualSelector = bytes4(self.call.returnData);

        if (actualSelector != expectedSelector) {
            printMessage(message);
            console.log("Error: call expected to revert with selector [call]");
            console.log("  Expected error", strings.toString(bytes32(expectedSelector)));
            console.log("    Actual error", strings.toString(bytes32(actualSelector)));

            vulcan.fail();
        }
    }

function toHaveRevertedWith(_CallExpectation memory self, bytes memory expectedError, string memory message)
        internal
    {
        self.toHaveReverted();

        bytes32 expectedHash = keccak256(expectedError);
        bytes32 actualHash = keccak256(self.call.returnData);

        if (!self.call.success && actualHash != expectedHash) {
            printMessage(message);
            console.log("Error: function expected to revert with error [call]");
            console.log("  Expected error", strings.toString(expectedError));
            console.log("    Actual error", strings.toString(self.call.returnData));

            vulcan.fail();
        }
    }

function flashLoan(uint256 borrowAmount) external nonReentrant {
    uint256 balanceBefore = token.balanceOf(address(this));
    require(balanceBefore >= borrowAmount, "Not enough tokens in pool");

    token.transfer(msg.sender, borrowAmount);

    require(msg.sender.isContract(), "Sender must be a deployed contract");
    (bool success,) = msg.sender.call(
        abi.encodeWithSignature(
            "receiveTokens(address,uint256)",
            address(token),
            borrowAmount
        )
    );
    require(success, "External call failed");

    uint256 balanceAfter = token.balanceOf(address(this));

    require(balanceAfter >= balanceBefore, "Flash loan hasn't been paid back");
}

function checkUpkeep(bytes calldata) external view returns (bool, bytes memory) {
  // DEV: start at a random spot in the list so that checks are
  // spread evenly among cron jobs
  uint256 numCrons = s_activeCronJobIDs.length();
  if (numCrons == 0) {
    return (false, bytes(""));
  }
  uint256 startIdx = block.number % numCrons;
  bool result;
  bytes memory payload;
  (result, payload) = checkInRange(startIdx, numCrons);
  if (result) {
    return (result, payload);
  }
  (result, payload) = checkInRange(0, startIdx);
  if (result) {
    return (result, payload);
  }
  return (false, bytes(""));
}

function __supportMarket(VToken vToken) internal returns (uint256) {
    ensureAllowed("_supportMarket(address)");

    if (getCorePoolMarket(address(vToken)).isListed) {
        return fail(Error.MARKET_ALREADY_LISTED, FailureInfo.SUPPORT_MARKET_EXISTS);
    }

    vToken.isVToken(); // Sanity check to make sure its really a VToken

    // Note that isVenus is not in active use anymore
    Market storage newMarket = getCorePoolMarket(address(vToken));
    newMarket.isListed = true;
    newMarket.isVenus = false;
    newMarket.collateralFactorMantissa = 0;

    _addMarketInternal(vToken);
    _initializeMarket(address(vToken));

    emit MarketListed(vToken);

    return uint256(Error.NO_ERROR);
}

function unwrap(
    uint256 amount,
    address recipient
) external lock onlyAlchemist returns (uint256) {
    SafeERC20.safeTransferFrom(token, msg.sender, address(this), amount);

    uint256 startingBalance = IERC20(underlyingToken).balanceOf(address(this));

    uint256 error;
    if ((error = ICERC20(token).redeem(amount)) != NO_ERROR) {
        revert FuseError(error);
    }

    uint256 endingBalance = IERC20(underlyingToken).balanceOf(address(this));
    uint256 redeemedAmount = endingBalance - startingBalance;

    SafeERC20.safeTransfer(underlyingToken, recipient, redeemedAmount);

    return redeemedAmount;
}

