        revert InvalidArguments("Invalid userName or message");
    }

    console2.log("Memo Created By:", userName);

    memos.push(Memo(userName, message, block.timestamp, msg.sender));

    emit NewMemo(msg.sender, block.timestamp, userName, message);

    console2.log("New Memo was emitted");
}

function updateOrderPoolAfterExecution(
    LongTermOrders storage longTermOrders,
    OrderPool storage orderPool0,
    OrderPool storage orderPool1,
    uint256 token0Out,
    uint256 token1Out,
    uint256 blockTimestamp
) private {
    //distribute proceeds to pools
    orderPoolDistributePayment(orderPool0, token1Out);
    orderPoolDistributePayment(orderPool1, token0Out);
    emit Value("token0Out", token0Out);
    emit Value("token1Out", token1Out);

    //handle orders expiring at end of interval
    orderPoolUpdateStateFromBlockExpiry(orderPool0, blockTimestamp);
    orderPoolUpdateStateFromBlockExpiry(orderPool1, blockTimestamp);

    //update last virtual trade block
    longTermOrders.lastVirtualOrderTimestamp = blockTimestamp;
}

function removeAMO(address amo_address) external onlyByOwnGov {
    require(amo_address != address(0), "Zero address detected");
    require(amos[amo_address] == true, "Address nonexistent");

    // Delete from the mapping
    delete amos[amo_address];

    // 'Delete' from the array by setting the address to 0x0
    for (uint i = 0; i < amos_array.length; i++){
        if (amos_array[i] == amo_address) {
            amos_array[i] = address(0); // This will leave a null in the array and keep the indices the same
            break;
        }
    }

    emit AMORemoved(amo_address);
}

