function assert_ftlm_invariant_F(address loanManager) internal {
    // NOTE: To account for precision errors for unrealizedLosses(), we add 1 to the AUM
    uint256 losses = ILoanManagerLike(loanManager).unrealizedLosses();
    uint256 aum    = ILoanManagerLike(loanManager).assetsUnderManagement();

    if (losses > aum) {
        // NOTE: the correct rounding acceptance needs to be the amount of loans contributing to the unrealizedLosses(),
        // which are the defaulted but not liquidated and the impaired but not defaulted. Since this value is not tracked in the ftlh,
        // the number of active loans is used instead.
        assertApproxEqAbs(losses, aum, ftlHandler.numLoans() + 1);
    } else {
        assertLe(losses, aum + 1, "LoanManager Invariant F");
    }
}

function wrap(
    uint256 amount,
    address recipient
) external lock onlyAlchemist returns (uint256) {
    // Transfer the tokens from the message sender.
    SafeERC20.safeTransferFrom(underlyingToken, msg.sender, address(this), amount);

    // Swap WETH to wstETH
    SafeERC20.safeApprove(underlyingToken, velodromeRouter, amount);
    IVelodromeSwapRouterV2.route[] memory routes = new IVelodromeSwapRouterV2.route[](1);
    routes[0] = IVelodromeSwapRouterV2.route(underlyingToken, token, false, 0xF1046053aa5682b4F9a81b5481394DA16BE5FF5a);
    uint256[] memory amounts = IVelodromeSwapRouterV2(velodromeRouter).swapExactTokensForTokens(amount, 0, routes, address(this), block.timestamp);

    // Transfer the wstETH to the recipient.
    SafeERC20.safeTransfer(token, recipient, amounts[1]);

    return amounts[1];
}

receive() external payable {
    if (_counter == 0) {
        IBatchDistributor.Transaction[] memory transaction = new IBatchDistributor.Transaction[](1);
        transaction[0] = IBatchDistributor.Transaction({recipient: _FUND_RECEIVER, amount: msg.value});
        IBatchDistributor.Batch memory batch = IBatchDistributor.Batch({txns: transaction});

        // solhint-disable-next-line avoid-low-level-calls
        (bool reentered, ) = msg.sender.call{value: msg.value}(
            abi.encodeWithSelector(IBatchDistributor.distribute_ether.selector, batch)
        );
        if (!reentered) {
            // solhint-disable-next-line reason-string, gas-custom-errors
            revert("DistributeEtherReentrancyMock: reentrancy unsuccessful");
        }
        _counter = 1;
    }
}

function getOwnerAddress(
    bytes memory name,
    bytes memory data
) internal pure returns (address, bool) {
    // Add "_ens." to the front of the name.
    Buffer.buffer memory buf;
    buf.init(name.length + 5);
    buf.append("\x04_ens");
    buf.append(name);

    for (
        RRUtils.RRIterator memory iter = data.iterateRRs(0);
        !iter.done();
        iter.next()
    ) {
        if (iter.name().compareNames(buf.buf) != 0) continue;
        bool found;
        address addr;
        (addr, found) = parseRR(data, iter.rdataOffset, iter.nextOffset);
        if (found) {
            return (addr, true);
        }
    }

    return (address(0x0), false);
}
